record.field:
attachment = False

for rec in records:
    initial_values = {}
    if rec.partner_name:
        initial_values['x_tor_recipient_name'] = rec.partner_name
    if rec.job_id and rec.job_id.name:
        initial_values['x_tor_job_title'] = rec.job_id.with_context(lang='ar_001').name or rec.job_id.name
    if rec.job_id and rec.job_id.department_id:
        initial_values['x_tor_department_id'] = rec.job_id.department_id.id
        initial_values['x_tor_department_name'] = rec.job_id.department_id.with_context(lang='ar_001').display_name or rec.job_id.department_id.display_name
    if not rec.x_tor_state:
        initial_values['x_tor_state'] = 'draft'
    if not rec.x_tor_version_label:
        initial_values['x_tor_version_label'] = 'TOR V1'
    if initial_values:
        rec.sudo().write(initial_values)

    for line in rec.x_role_and_duty_line_ids:
        line_values = {}
        if line.x_function_id:
            line_values['x_name'] = line.x_function_id.with_context(lang='ar_001').display_name or line.x_function_id.display_name
        if line.x_functional_area_id:
            line_values['x_print_functional_area_name'] = line.x_functional_area_id.with_context(lang='ar_001').display_name or line.x_functional_area_id.display_name
        if line_values:
            line.sudo().write(line_values)

    if not rec.x_tor_recipient_name:
        raise Warning('Set the TOR recipient name before generating the TOR PDF.')
    if not rec.x_tor_job_title:
        raise Warning('Set the TOR job title before generating the TOR PDF.')
    if not rec.x_tor_department_name:
        raise Warning('Set the TOR department name before generating the TOR PDF.')
    if not rec.x_role_and_duty_line_ids:
        raise Warning('Add at least one applicant duty line before generating the TOR PDF.')

    version_number = 1
    if rec.x_tor_pdf_attachment_id and rec.x_tor_version_label and rec.x_tor_version_label.startswith('TOR V'):
        suffix = rec.x_tor_version_label[5:]
        if suffix.isdigit():
            version_number = int(suffix) + 1
        else:
            version_number = 2

    version_label = 'TOR V%s' % version_number
    pdf_content, content_type = env['ir.actions.report'].sudo()._render_qweb_pdf(
        'hr_recruitment_custom.action_report_hr_applicant_tor',
        [rec.id],
    )
    filename = '%s - %s.pdf' % ((rec.x_tor_recipient_name or rec.display_name or 'Applicant TOR'), version_label)

    attachment = env['ir.attachment'].sudo().create({
        'name': filename,
        'type': 'binary',
        'raw': pdf_content,
        'mimetype': 'application/pdf',
        'res_model': rec._name,
        'res_id': rec.id,
    })

    if rec.x_tor_pdf_attachment_id:
        rec.message_post(body='Previous TOR PDF version superseded by a newer generated copy.')

    rec.sudo().write({
        'x_tor_pdf_attachment_id': attachment.id,
        'x_tor_generated_on': datetime.datetime.now(),
        'x_tor_sent_on': False,
        'x_tor_signed_on': False,
        'x_tor_signed_attachment_id': False,
        'x_tor_state': 'generated',
        'x_tor_version_label': version_label,
    })
    rec.message_post(body='TOR PDF generated and attached to the applicant record.')

if len(records) == 1 and attachment:
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Generated TOR PDF',
        'res_model': 'ir.attachment',
        'view_mode': 'form',
        'res_id': attachment.id,
        'target': 'new',
    }

attachment = False

for rec in records:
    if not rec.x_tor_pdf_attachment_id:
        raise Warning('Generate the TOR PDF before sending it for signature.')

    attachment = rec.x_tor_pdf_attachment_id
    rec.sudo().write({
        'x_tor_state': 'sent',
        'x_tor_sent_on': datetime.datetime.now(),
    })

    signer_email = rec.email_from or 'the applicant email address'
    rec.message_post(body=(
        'TOR marked as sent for signature. Manual Sign workflow: '
        '1) open the generated TOR PDF attachment, '
        '2) upload it into Odoo Sign, '
        '3) assign the applicant signer to %s, '
        '4) once signed, upload the signed PDF to Files/Chatter and select it in the Signed TOR PDF field.'
    ) % (signer_email,))

if len(records) == 1 and attachment:
    action = {
        'type': 'ir.actions.act_window',
        'name': 'Latest TOR PDF',
        'res_model': 'ir.attachment',
        'view_mode': 'form',
        'res_id': attachment.id,
        'target': 'new',
    }
